    } catch (error) {
      console.error('Failed to export calls:', error);
    }
  };

  const formatDuration = (seconds) => {
    if (!seconds) return '0:00';
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const formatTime = (isoString) => {
    if (!isoString) return '-';
    const date = new Date(isoString);
    return date.toLocaleString();
  };

  const filteredCalls = calls.filter(call => {
    // Search filter
    if (searchQuery && !JSON.stringify(call).toLowerCase().includes(searchQuery.toLowerCase())) {
      return false;
    }

    // Status filter
    if (filterStatus !== 'all' && call.status !== filterStatus) {
      return false;
    }

    // Disposition filter
    if (filterDisposition !== 'all' && call.disposition !== filterDisposition) {
      return false;
    }

    return true;
  });

  return (
    <div className="call-history">
      <div className="history-header">
        <h2>Call History</h2>
        <div className="header-actions">
          <button 
            className="btn-export"
            onClick={exportCalls}
          >
            <Download size={16} />
            Export CSV
          </button>
        </div>
      </div>

      {/* Active Calls Section */}
      {activeCalls.length > 0 && (
        <div className="active-calls-section">
          <h3 className="section-title">
            <PhoneCall className="pulse" />
            Active Calls ({activeCalls.length})
          </h3>
          <div className="active-calls-grid">
            {activeCalls.map(call => (
              <div key={call.uuid} className="active-call-card">
                <div className="call-header">
                  <span className="phone-number">{call.phone_number}</span>
                  <span className="duration-live">
                    <Clock size={14} />
                    {formatDuration(call.duration)}
                  </span>
                </div>
                <div className="call-details">
                  <span className="lead-name">
                    <User size={14} />
                    {call.lead_name}
                  </span>
                  <span className="bot-info">Bot {call.bot_port}</span>
                </div>
                <div className="call-actions">
                  <Link 
                    to={`/call/${call.uuid}`}
                    className="btn-monitor"
                  >
                    Monitor
                  </Link>
                  <button className="btn-hangup">
                    <PhoneOff size={14} />
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

